supplément).'),(4,'Menu Pâques Familial',12,35,'Un menu festif pour réunir toute la famille autour de spécialités de Pâques.',6,1,2,'https://images.unsplash.com/photo-1555939594-58d7cb561ad1?w=600&q=80','Commande à passer au minimum 72h à l\'avance pour les fêtes de Pâques. Minimum 8 personnes. Annulation possible jusqu\'à 48h avant.'),(5,'Menu Vegan Été',6,28,'Un menu 100% vegan avec des légumes de saison cultivés localement.',12,3,4,'https://images.unsplash.com/photo-1540189549336-e6e99c3679fe?w=600&q=80','Commande à passer au minimum 48h à l\'avance. Menu 100% vegan, sans produit d\'origine animale. Certification vegan disponible sur demande.'),(6,'Menu Mariage Prestige',50,65,'Notre menu le plus raffiné pour les grands événements, avec foie gras et magret de canard.',3,1,4,'https://images.unsplash.com/photo-1519225421980-715cb0215aed?w=600&q=80','Commande à passer au minimum 7 jours à l\'avance. Minimum 30 personnes. Un acompte de 30% est demandé à la réservation. Service traiteur inclus.'),(7,'Menu Entreprise Classique',20,40,'Idéal pour vos repas d\'affaires, un menu élégant et sobre qui plaira à tous.',7,1,3,'https://images.unsplash.com/photo-1517248135467-4c7edcad34c4?w=600&q=80','Commande à passer au minimum 48h à l\'avance. Facture entreprise disponible. Livraison sur site possible dans un rayon de 50 km.'),(8,'Menu Végétarien Noël',10,42,'Célébrez Noël sans viande avec ce menu végétarien festif et généreux.',4,2,1,'https://images.unsplash.com/photo-1467003909585-2f8a72700288?w=600&q=80','Commande à passer au minimum 48h à l\'avance. Menu végétarien adapté aux fêtes de fin d\'année. Sans viande ni poisson. Personnalisation sur demande.'),(9,'Menu Cocktail Événement',30,25,'Un menu cocktail dinatoire parfait pour vos soirées et événements professionnels.',15,1,4,'https://images.unsplash.com/photo-1529543544282-ea669407fca3?w=600&q=80','Commande à passer au minimum 72h à l\'avance. Minimum 20 personnes. Personnel de service disponible en option. Vaisselle et nappage inclus.'),(10,'Menu Terroir Bordelais',8,55,'Le meilleur de la gastronomie bordelaise : huîtres, lamproie, entrecôte et cannelés.',5,1,3,'https://images.unsplash.com/photo-1504674900247-0877df9cc836?w=600&q=80','Commande à passer au minimum 48h à l\'avance. Produits du terroir bordelais certifiés. Accord mets-vins proposé en option (supplément).'); /*!40000 ALTER TABLE `menu` ENABLE KEYS */; UNLOCK TABLES;  -- -- Table structure for table `menu_image` --  DROP TABLE IF EXISTS `menu_image`; /*!40101 SET @saved_cs_client     = @@character_set_client */; /*!50503 SET character_set_client = utf8mb4 */; CREATE TABLE `menu_image` (   `id` int NOT NULL AUTO_INCREMENT,   `url` varchar(500) NOT NULL,   `alt` varchar(255) NOT NULL,   `menu_id` int NOT NULL,   PRIMARY KEY (`id`),   KEY `IDX_54912738CCD7E912` (`menu_id`),   CONSTRAINT `FK_54912738CCD7E912` FOREIGN KEY (`menu_id`) REFERENCES `menu` (`id`) ON DELETE CASCADE ) ENGINE=InnoDB AUTO_INCREMENT=35 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_0900_ai_ci ROW_FORMAT=DYNAMIC; /*!40101 SET character_set_client = @saved_cs_client */;  -- -- Dumping data for table `menu_image` --  LOCK TABLES `menu_image` WRITE; /*!40000 ALTER TABLE `menu_image` DISABLE KEYS */; INSERT INTO `menu_image` VALUES (1,'https://images.unsplash.com/photo-1543353071-087092ec393a?w=800','Dinde rôtie aux herbes pour le réveillon',1),(2,'https://images.unsplash.com/photo-1607478900766-efe13248b125?w=800','Bûche de Noël au chocolat',1),(3,'https://images.unsplash.com/photo-1576021182211-9ea8dced3690?w=800','Foie gras et toast pour Noël',1),(4,'https://images.unsplash.com/photo-1513558161293-cdaf765ed2fd?w=800','Champagne et mise en bouche festive',1),(5,'https://images.unsplash.com/photo-1512621776951-a57141f2eefd?w=800','Salade colorée de légumes printaniers',2),(6,'https://images.unsplash.com/photo-1540420773420-3366772f4999?w=800','Assiette de légumes grillés',2),(7,'https://images.unsplash.com/photo-1490645935967-10de6ba17061?w=800','Tarte aux lég